70	// MARK: - BluetoothManagerProtocol
71	
72	extension BluetoothManagerImpl: BluetoothManager {
73	
74	    var observeDevice: AnyPublisher<RadiaCode, Never> {
75	        devicesObserver.eraseToAnyPublisher()
76	    }
77	
78	    var observeScanningStatus: AnyPublisher<Bool, Never> {
79	        centralManager.publisher(for: \.isScanning)
80	            .assertNoFailure()
81	            .removeDuplicates()
82	            .eraseToAnyPublisher()
83	    }
84	
85	    func startScan() {
86	        searchingObserver.send(true)
87	    }
88	
89	    func stopScan() {
90	        centralManager.stopScan()
91	        searchingObserver.send(false)
92	    }
93	
94	    func connect(device: CBPeripheral) {
95	        centralManager.connect(device, options: [CBConnectPeripheralOptionNotifyOnDisconnectionKey: true])
96	    }
97	
98	    func disconnect(device: CBPeripheral) async throws {
99	        try await withCheckedThrowingContinuation { continuation in
100	            disconnectContinuation = continuation
101	            centralManager.cancelPeripheralConnection(device)
102	        }
103	    }
104	    
105	    func setupReconnection(device: CBPeripheral) {
106	        reconnectionCancellable = bleStatusObserver
107	            .filter { $0 }
108	            .sink { [weak self] _ in
109	                guard let self = self else { return }
110	                self.connect(device: device)
111	            }
112	    }
113	}
114	
115	// MARK: - Private methods
116	private extension BluetoothManagerImpl {
117	
118	    func setupObservers() {
119	        bleStatusObserver.combineLatest(searchingObserver)
120	            .assertNoFailure()
121	            .map { $0 && $1 }
122	            .sink { [weak self] isReady in
123	                guard let self = self else { return }
124	                if isReady {
125	                    // self.centralManager.retrieveConnectedPeripherals(withServices: [CBUUID])
126	                    self.centralManager.scanForPeripherals(withServices: [Consts.radiaCodeServiceCBUUID], options: [CBCentralManagerScanOptionAllowDuplicatesKey: true])
127	                }
128	            }
129	            .store(in: &cancellable)
130	    }
131	}
