133	// MARK: - CBCentralManagerDelegate
134	extension BluetoothManagerImpl: CBCentralManagerDelegate {
135	
136	    func centralManagerDidUpdateState(_ central: CBCentralManager) {
137	        switch central.state {
138	        case .unknown:
139	            bluetoothStatus.send(.unknown)
140	        case .resetting:
141	            bluetoothStatus.send(.unknown)
142	        case .unsupported:
143	            bluetoothStatus.send(.unknown)
144	        case .unauthorized:
145	            bluetoothStatus.send(.notAuthorized)
146	        case .poweredOff:
147	            bleStatusObserver.send(false)
148	            bluetoothStatus.send(.poweredOff)
149	        case .poweredOn:
150	            bleStatusObserver.send(true)
151	            bluetoothStatus.send(.poweredOn)
152	        @unknown default:
153	            bluetoothStatus.send(.unknown)
154	        }
155	    }
156	
157	    func centralManager(
158	        _ central: CBCentralManager,
159	        didDiscover peripheral: CBPeripheral,
160	        advertisementData: [String: Any],
161	        rssi RSSI: NSNumber
162	    ) {
163	        let localName = DeviceBluetoothConstants.PeripheralAdvertisementKeys.localName.rawValue
164	
165	        guard let name = peripheral.name, let localName = advertisementData[localName] as? String else {
166	            return
167	        }
168	        
169	        let peripheralName = name.contains(RadiaCode.Model.defaultName) ? name : localName
170	
171	        guard peripheralName.hasPrefix(RadiaCode.Model.defaultName) else {
172	            return
173	        }
174	
175	        let splittedName = peripheralName.components(separatedBy: "#")
176	
177	        let deviceId: String
178	        let deviceName: String
179	
180	        if splittedName.count == 2 {
181	            deviceId = splittedName[1]
182	            deviceName = splittedName[0]
183	        } else {
184	            deviceId = peripheral.identifier.uuidString
185	            deviceName = RadiaCode.Model.defaultName
186	        }
187	
188	        let foundDevice = RadiaCode(
189	            device: .init(identifier: deviceId, model: deviceName),
190	            signal: .init(doubleValue: RSSI.doubleValue),
191	            connection: peripheral
192	        )
193	        devicesObserver.send(foundDevice)
194	    }
195	
196	    func centralManager(_ central: CBCentralManager, didConnect peripheral: CBPeripheral) {
197	        peripheral.discoverServices([Consts.radiaCodeServiceCBUUID])
198	        peripheral.readRSSI()
199	    }
200	
201	    func centralManager(_ central: CBCentralManager, didDisconnectPeripheral peripheral: CBPeripheral, error: Error?) {
202	        if let continuation = disconnectContinuation {
203	            disconnectContinuation = nil
204	            if let disconnectError = error {
205	                continuation.resume(throwing: disconnectError)
206	            } else {
207	                continuation.resume()
208	            }
209	        }
210	    }
211	}
