12	final class WatchConnectivity: NSObject {
13	     
14	    var radiationLevelViewModel: RadiationLevelViewModel = .init()
15	    var searchViewModel: SearchViewModel
16	
17	    private let countRateSubject = PassthroughSubject<DataBufferBatch, Never>()
18	    private let doseRateSubject  = PassthroughSubject<DataBufferBatch, Never>()
19	    
20	    private let session: WCSession
21	
22	    override init() {
23	        self.session = .default
24	        
25	        self.searchViewModel = SearchViewModel(
26	            countRateRawPublisher: countRateSubject.eraseToAnyPublisher(),
27	            doseRateRawPublisher: doseRateSubject.eraseToAnyPublisher()
28	        )
29	        super.init()
30	        session.delegate = self
31	        session.activate()
32	    }
