35	extension WatchConnectivity: WCSessionDelegate {
36	
37	    func session(_ session: WCSession, didReceiveMessage message: [String: Any], replyHandler: @escaping ([String: Any]) -> Void) {
38	        parseMessage(message, replyHandler: replyHandler)
39	    }
40	    
41	    func session(_ session: WCSession, didReceiveUserInfo userInfo: [String: Any] = [:]) {
42	        parseMessage(userInfo)
43	    }
44	            
45	    private func parseMessage(_ message: [String: Any], replyHandler: (([String: Any]) -> Void)? = nil) {
46	        Task {
47	            if let countRateDictionary = message[SharedKeys.countRate] as? [String: Any], let countRate = RadiationData.fromDictionary(countRateDictionary) {
48	                await MainActor.run {
49	                    self.radiationLevelViewModel.countRate = countRate
50	                }
51	            }
52	            
53	            if let doseRateDictionary = message[SharedKeys.doseRate] as? [String: Any], let doseRate = RadiationData.fromDictionary(doseRateDictionary) {
54	                await MainActor.run {
55	                    self.radiationLevelViewModel.doseRate = doseRate
56	                }
57	            }
58	            
59	            if let alarmsDictionary = message[SharedKeys.alarms] as? [String: Any], let alarm = Alarm.fromDictionary(alarmsDictionary) {
60	                await MainActor.run {
61	                    self.searchViewModel.alarms = alarm
62	                }
63	            }
64	            
65	            if let countRateRawDictionary = message[SharedKeys.countRateRaw] as? [String: Any], let countRateRaw = DataBufferBatch.fromDictionary(countRateRawDictionary) {
66	                countRateSubject.send(countRateRaw)
67	            }
68	            
69	            if let doseRateRawDictionary = message[SharedKeys.doseRateRaw] as? [String: Any], let doseRateRaw = DataBufferBatch.fromDictionary(doseRateRawDictionary) {
70	                doseRateSubject.send(doseRateRaw)
71	            }
72	        }
73	    }
74	        
75	    func session(_ session: WCSession, activationDidCompleteWith activationState: WCSessionActivationState, error: (any Error)?) {}
76	}
