8	import Foundation
9	
10	protocol BluetoothCommand: BluetoothCommandRequestConfigurator,
11	                           BluetoothRequestPackage,
12	                           BluetoothCommandResponseProvider,
13	                           BluetoothRawStorageProvider {
14	}
15	
16	extension BluetoothCommand {
17	        
18	    var request: BluetoothCommandRequestBuilder<BluetoothCommandRequest> {
19	        .init { result in
20	            let dataWithSize: [UInt8] = UInt32(result.count).asBytes + result
21	            /// Максимальный размер отправляемого пакеты команды составляет 18 байт
22	            return dataWithSize.chunks(by: 18).map { Data($0) }
23	        }
24	    }
25	    
26	    var response: BluetoothCommandResponseBuilder<BluetoothDefaultResponse> {
27	        .init { storage in
28	            return .init(isValid: storage.isValid)
29	        }
30	    }
31	    
32	    var storageType: StorageType {
33	        .default
34	    }
35	    
36	    var identifier: String {
37	        "\(Self.self)"
38	    }
39	}
